import React from "react";

const Home = () => {
  return (
    <div className="home-container">
      <div className="home-bg" />
      <div className="home-content">
        <h1>Web Developer & MERN Enthusiast</h1>
        <h2>Hi, I am PRAGATHESWARAN A</h2>
        <p>
          Enthusiastic software developer with a strong foundation in web
          development, Python, and C, passionate about building modern,
          efficient, and sustainable digital solutions. [file:1]
        </p>
        <a href="#contact" className="primary-btn">Hire Me</a>
        <a href="#projects" className="secondary-btn">View Projects</a>
        <a
          href="/PRAGATHESWARAN_RESUME.pdf"
          className="secondary-btn"
          download
        >
          Download Resume
        </a>
      </div>
    </div>
  );
};

export default Home;
